{
  "version": 2,
  "data_sources": {
    "tables": [
      {
        "identifier": "main.money_stg.vw_deposit",
        "description": [
          "This is the central source of truth for all Global Deposits. It tracks successful funding events across various company platforms, including the IBAN and Trading platforms. Each row represents a single deposit transaction. Use this table for analyzing deposit volume, frequency, and platform-specific performance"
        ],
        "column_configs": [
          {
            "column_name": "AccountType",
            "description": [
              "The specific platform receiving the funds (e.g., 'Trading', 'IBAN'). Use this to compare performance between different product offerings."
            ],
            "enable_format_assistance": true,
            "enable_entity_matching": true
          },
          {
            "column_name": "AmountInUSD",
            "description": [
              "The gross value of the deposit converted to USD. This column is 100% populated. Always sum this for \"Total Deposit Volume.\""
            ],
            "enable_format_assistance": true
          },
          {
            "column_name": "Country",
            "description": [
              "The customer's country of residence at the time of the transaction."
            ],
            "enable_format_assistance": true,
            "enable_entity_matching": true
          },
          {
            "column_name": "Date",
            "description": [
              "The primary timestamp for the transaction. Use this for daily, monthly, or yearly deposit trends."
            ],
            "enable_format_assistance": true
          },
          {
            "column_name": "FundingType",
            "description": [
              "The payment method used for the deposit (e.g., Credit Card, Wire Transfer, E-wallet)."
            ],
            "enable_format_assistance": true,
            "enable_entity_matching": true
          },
          {
            "column_name": "GCID",
            "description": [
              "Global Customer Identifier. A single GCID can have multiple rows here. Use COUNT(DISTINCT GCID) for active depositor counts."
            ],
            "enable_format_assistance": true
          },
          {
            "column_name": "MIMOPlatform",
            "enable_format_assistance": true,
            "enable_entity_matching": true
          }
        ]
      }
    ]
  },
  "instructions": {
    "text_instructions": [
      {
        "id": "01f0eaf4a5581b13a940e216223a8374",
        "content": [
          "When asked about \"Total Deposits,\" use the vw_deposit table.\r\n",
          "\r\n",
          "When asked about \"New Customers\" or \"Conversion,\" use the vw_ftd table.\r\n",
          "\r\n",
          "Retention Metric: To find \"Repeat Depositors,\" count GCIDs in vw_deposit that have more than one row.\r\n",
          "\r\n",
          "Platform Mix: If a user asks \"Where is the money going?\", group by AccountType."
        ]
      }
    ]
  }
}
